## Gradient Text Implementation

The logo should be rendered with a gradient effect from the primary color (cyan) to secondary color (purple) to create visual interest.

### File: crates/fastmcp-console/src/banner.rs (partial)

```rust
use rich_rust::prelude::*;
use crate::theme::theme;

/// ASCII art logo variants
pub const LOGO_FULL: &str = r#"..."#;  // Full logo above
pub const LOGO_COMPACT: &str = r#"..."#;  // Compact logo
pub const LOGO_MINIMAL: &str = "FastMCP Rust";

/// Choose appropriate logo based on terminal width
pub fn choose_logo(width: usize) -> &'static str {
    if width >= 50 {
        LOGO_FULL
    } else if width >= 30 {
        LOGO_COMPACT
    } else {
        LOGO_MINIMAL
    }
}

/// Render text with a vertical gradient between two colors
pub fn gradient_text(text: &str, start: &Color, end: &Color) -> String {
    let lines: Vec<&str> = text.lines().collect();
    let line_count = lines.len().max(1);

    let mut result = String::new();

    for (i, line) in lines.iter().enumerate() {
        // Calculate interpolation factor (0.0 to 1.0)
        let t = i as f64 / (line_count - 1).max(1) as f64;

        // Interpolate RGB values
        let color = interpolate_colors(start, end, t);

        // Format with color
        result.push_str(&format!("[{}]{}[/]\n", color.hex(), line));
    }

    result
}

/// Linear interpolation between two colors
fn interpolate_colors(start: &Color, end: &Color, t: f64) -> Color {
    // Get RGB triplets
    let start_rgb = start.get_triplet().unwrap_or(ColorTriplet::new(0, 212, 255));
    let end_rgb = end.get_triplet().unwrap_or(ColorTriplet::new(168, 85, 247));

    // Interpolate each channel
    let r = lerp(start_rgb.red, end_rgb.red, t);
    let g = lerp(start_rgb.green, end_rgb.green, t);
    let b = lerp(start_rgb.blue, end_rgb.blue, t);

    Color::from_rgb(r, g, b)
}

fn lerp(a: u8, b: u8, t: f64) -> u8 {
    let a = a as f64;
    let b = b as f64;
    (a + (b - a) * t).round() as u8
}

/// Render logo with gradient (or plain fallback)
pub fn render_logo(console: &FastMcpConsole) {
    let width = console.width();
    let logo = choose_logo(width);

    if console.is_rich() {
        let theme = console.theme();
        let gradient = gradient_text(logo, &theme.primary, &theme.secondary);
        console.print(&gradient);
    } else {
        // Plain fallback
        console.print_plain(logo);
    }
}
```

